/**
 * Pre-build stamp: generates packages/mcp-server-core/src/build-info.ts
 * with the plugin version (from root package.json).
 *
 * Called by `npm run build:plugin` via the prebuild:plugin lifecycle hook.
 * The generated file is committed to src/ so tsc picks it up; it is also
 * listed in .gitignore-exempt so the build is reproducible from any clone.
 *
 * Usage: node scripts/stamp-build-info.mjs
 */
import { readFileSync, writeFileSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const root = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const rootPkg = JSON.parse(readFileSync(path.join(root, "package.json"), "utf8"));
const version = rootPkg.version;

const out = `\
// AUTO-GENERATED by scripts/stamp-build-info.mjs — do not edit by hand.
// Regenerated on every \`npm run build:plugin\`.
export const PLUGIN_VERSION = '${version}';
`;

const targets = [
  "packages/mcp-server-core/src/build-info.ts",
  "plugins/claude-code/src/version.ts",
  "plugins/codex/src/version.ts",
  "plugins/cursor/src/version.ts",
  "plugins/antigravity/src/version.ts",
];
for (const rel of targets) {
  writeFileSync(path.join(root, rel), out, "utf8");
}
console.error(`stamped build-info: v${version}`);
